__device__ void bit_reverse(uint64_t *a, int n, int lane) {
    if(lane==0) {
        for(int i=1,j=0;i<n;i++) {
            int bit=n>>1;
            for(;j&bit;bit>>=1) j^=bit;
            j^=bit;
            if(i<j) {uint64_t t=a[i];a[i]=a[j];a[j]=t;}
        }
    }
    __syncthreads();
}

__device__ void fast_ntt(uint64_t *a, int n, bool invert,
                          uint64_t p, const uint64_t *roots,
                          const uint64_t *iroots, uint64_t inv_n, int lane) {
    bit_reverse(a, n, lane);
    for(int length=2; length<=n; length<<=1) {
        int half=length>>1, step=n/length;
        int total=(n/length)*half;
        for(int idx=lane; idx<total; idx+=blockDim.x) {
            int group=idx/half, k=idx%half, base=group*length;
            uint64_t wn=invert?iroots[k*step]:roots[k*step];
            uint64_t u=a[base+k], v=a[base+k+half]*wn%p;
            a[base+k]=(u+v)%p;
            a[base+k+half]=(u-v+p)%p;
        }
        __syncthreads();
    }
    if(invert) {
        for(int i=lane;i<n;i+=blockDim.x) a[i]=a[i]*inv_n%p;
        __syncthreads();
    }
}

// LEN*LEN -> 2*LEN，用NTT_S=256点
__device__ void ntt_mul_s(
    uint32_t *a, uint32_t *b, uint32_t *c,
    uint64_t *fa1, uint64_t *fb1, uint64_t *fa2, uint64_t *fb2,
    int alen, int lane
) {
    for(int i=lane;i<NTT_S;i+=blockDim.x) {
        fa1[i]=i<alen?a[i]:0; fb1[i]=i<alen?b[i]:0;
        fa2[i]=i<alen?a[i]:0; fb2[i]=i<alen?b[i]:0;
    }
    __syncthreads();
    fast_ntt(fa1,NTT_S,false,P1,RS1,IRS1,INV_NS1,lane);
    fast_ntt(fb1,NTT_S,false,P1,RS1,IRS1,INV_NS1,lane);
    fast_ntt(fa2,NTT_S,false,P2,RS2,IRS2,INV_NS2,lane);
    fast_ntt(fb2,NTT_S,false,P2,RS2,IRS2,INV_NS2,lane);
    for(int i=lane;i<NTT_S;i+=blockDim.x) {
        fa1[i]=fa1[i]*fb1[i]%P1;
        fa2[i]=fa2[i]*fb2[i]%P2;
    }
    __syncthreads();
    fast_ntt(fa1,NTT_S,true,P1,RS1,IRS1,INV_NS1,lane);
    fast_ntt(fa2,NTT_S,true,P2,RS2,IRS2,INV_NS2,lane);
    if(lane==0) {
        uint64_t carry=0;
        for(int i=0;i<2*LEN;i++) {
            uint64_t r1=i<NTT_S?fa1[i]:0, r2=i<NTT_S?fa2[i]:0;
            uint64_t t=(r2-r1%P2+P2)%P2*INV_P1_P2%P2;
            uint64_t val=r1+P1*t+carry;
            c[i]=(uint32_t)(val%BASE); carry=val/BASE;
        }
    }
    __syncthreads();
}

// 2*LEN*LEN -> 3*LEN，用NTT_L=512点
__device__ void ntt_mul_l(
    uint32_t *a, int alen, uint32_t *b, uint32_t *c, int clen,
    uint64_t *fa1, uint64_t *fb1, uint64_t *fa2, uint64_t *fb2,
    int lane
) {
    for(int i=lane;i<NTT_L;i+=blockDim.x) {
        fa1[i]=i<alen?a[i]:0; fb1[i]=i<LEN?b[i]:0;
        fa2[i]=i<alen?a[i]:0; fb2[i]=i<LEN?b[i]:0;
    }
    __syncthreads();
    fast_ntt(fa1,NTT_L,false,P1,RL1,IRL1,INV_NL1,lane);
    fast_ntt(fb1,NTT_L,false,P1,RL1,IRL1,INV_NL1,lane);
    fast_ntt(fa2,NTT_L,false,P2,RL2,IRL2,INV_NL2,lane);
    fast_ntt(fb2,NTT_L,false,P2,RL2,IRL2,INV_NL2,lane);
    for(int i=lane;i<NTT_L;i+=blockDim.x) {
        fa1[i]=fa1[i]*fb1[i]%P1;
        fa2[i]=fa2[i]*fb2[i]%P2;
    }
    __syncthreads();
    fast_ntt(fa1,NTT_L,true,P1,RL1,IRL1,INV_NL1,lane);
    fast_ntt(fa2,NTT_L,true,P2,RL2,IRL2,INV_NL2,lane);
    if(lane==0) {
        uint64_t carry=0;
        for(int i=0;i<clen;i++) {
            uint64_t r1=i<NTT_L?fa1[i]:0, r2=i<NTT_L?fa2[i]:0;
            uint64_t t=(r2-r1%P2+P2)%P2*INV_P1_P2%P2;
            uint64_t val=r1+P1*t+carry;
            c[i]=(uint32_t)(val%BASE); carry=val/BASE;
        }
    }
    __syncthreads();
}

__device__ void dev_sub(uint32_t *a, uint32_t *b, uint32_t *c, int len) {
    int64_t borrow=0;
    for(int i=0;i<len;i++) {
        int64_t d=(int64_t)a[i]-b[i]-borrow;
        if(d<0){d+=BASE;borrow=1;}else borrow=0;
        c[i]=(uint32_t)d;
    }
}

__device__ int dev_geq(uint32_t *a, uint32_t *b, int len) {
    for(int i=len-1;i>=0;i--) {
        if(a[i]>b[i])return 1;
        if(a[i]<b[i])return 0;
    }
    return 1;
}

__device__ void dev_shr(uint32_t *a, int k, uint32_t *out, int alen, int olen) {
    int ws=k/16, bs=k%16;
    for(int i=0;i<olen;i++) {
        int src=i+ws;
        uint32_t lo=src<alen?a[src]>>bs:0;
        uint32_t hi=(bs>0&&src+1<alen)?((a[src+1]<<(16-bs))&0xFFFF):0;
        out[i]=lo|hi;
    }
}

__device__ void barrett_full_ntt(
    uint32_t *x, uint32_t *n, uint32_t *R, uint32_t *r,
    uint32_t *xR, uint32_t *q, uint32_t *qn,
    uint64_t *fa1, uint64_t *fb1, uint64_t *fa2, uint64_t *fb2,
    int n_bits, int lane
) {
    // xR = x(2*LEN) * R(LEN) -> 3*LEN，用大NTT
    ntt_mul_l(x, 2*LEN, R, xR, 3*LEN, fa1, fb1, fa2, fb2, lane);

    // q = xR >> 2*n_bits
    if(lane==0) dev_shr(xR, 2*n_bits, q, 3*LEN, LEN);
    __syncthreads();

    // qn = q(LEN) * n(LEN) -> 2*LEN，用小NTT
    ntt_mul_s(q, n, qn, fa1, fb1, fa2, fb2, LEN, lane);

    if(lane==0) {
        dev_sub(x, qn, r, LEN);
        for(int i=0;i<3;i++)
            if(dev_geq(r,n,LEN)) dev_sub(r,n,r,LEN);
    }
    __syncthreads();
}

// shared memory:
// uint32: T,gcur,tmp,xR,q,qn,nloc,Rloc = (LEN+LEN+2*LEN+3*LEN+LEN+2*LEN+LEN+LEN)*4 = 12*LEN*4
// uint64: fa1,fb1,fa2,fb2 各NTT_L = 4*NTT_L*8

__global__ void ntt_modexp_kernel(
    uint32_t *g_all, uint32_t *m_all,
    uint32_t *n_all, uint32_t *R_all,
    uint32_t *out_all,
    int m_bits, int n_bits, int num_tasks
) {
    int task_id=blockIdx.x, lane=threadIdx.x;
    if(task_id>=num_tasks) return;

    uint32_t *g=g_all+task_id*LEN, *m=m_all+task_id*LEN;
    uint32_t *n=n_all+task_id*LEN, *R=R_all+task_id*LEN;
    uint32_t *out=out_all+task_id*LEN;

    extern __shared__ uint8_t smem_raw[];
    uint32_t *sm32=(uint32_t*)smem_raw;
    uint32_t *T=sm32, *gcur=sm32+LEN, *tmp=sm32+2*LEN;
    uint32_t *xR=sm32+4*LEN, *q=sm32+7*LEN, *qn=sm32+8*LEN;
    uint32_t *nloc=sm32+10*LEN, *Rloc=sm32+11*LEN;

    uint64_t *sm64=(uint64_t*)(sm32+12*LEN);
    uint64_t *fa1=sm64, *fb1=sm64+NTT_L;
    uint64_t *fa2=sm64+2*NTT_L, *fb2=sm64+3*NTT_L;

    for(int i=lane;i<LEN;i+=blockDim.x) {
        T[i]=(i==0)?1:0; gcur[i]=g[i];
        nloc[i]=n[i]; Rloc[i]=R[i];
    }
    __syncthreads();

    for(int i=0; i<m_bits; i++) {
        int m_bit=(m[i/16]>>(i%16))&1;
        if(m_bit) {
            ntt_mul_s(T,gcur,tmp,fa1,fb1,fa2,fb2,LEN,lane);
            barrett_full_ntt(tmp,nloc,Rloc,T,xR,q,qn,fa1,fb1,fa2,fb2,n_bits,lane);
        }
        ntt_mul_s(gcur,gcur,tmp,fa1,fb1,fa2,fb2,LEN,lane);
        barrett_full_ntt(tmp,nloc,Rloc,gcur,xR,q,qn,fa1,fb1,fa2,fb2,n_bits,lane);
    }

    for(int i=lane;i<LEN;i+=blockDim.x) out[i]=T[i];
}
